import * as React from 'react'
import {api_host} from "../utils/api";
import "./bazaar.css"
import {
    Avatar,
    Button,
    Divider,
    FormControl,
    InputLabel,
    List,
    ListItemAvatar,
    ListItemButton,
    ListItemText,
    MenuItem,
    Select,
    TextField,
    Typography,
} from '@mui/material'
import {useEffect, useState} from "react";
import {getLoginToken} from "../utils/storage";
import {TierToStars} from "../components/mappingTable";
import {itemInfo} from "../components/gadgets";


export function Bazaar() {

    // 市场模板
    const [bazaarItems, setBazaarItems] = useState<any>({
            "data": [
                {
                    "id": 1,
                    "building_name":"寻找摊贩……",
                    "building_id": 1,
                    "storage_id": 1,
                    "price": 0,
                    "price_type": 5,
                    "price_tire": 1,
                    "sale_type": 1,
                    "sale_tire": 2,
                    "sale_amount": 0,
                    "fresh_amount": 5
                },
                {
                    "id": 2,
                    "building_name":"寻找摊贩……",
                    "building_id": 1,
                    "storage_id": 3,
                    "price": 0,
                    "price_type": 5,
                    "price_tire": 1,
                    "sale_type": 1,
                    "sale_amount": 0,
                    "fresh_amount": 2.5
                }
            ],
            "status": "success"
        }
    )
    const [emptyBazaarItems, setEmptyBazaarItems] = useState<any>(false)
    //fetch市场物品
    useEffect(() => {
            fetch(api_host() + "/api/market", {
                method: "GET", // *GET, POST, PUT, DELETE, etc.
                mode: "cors", // no-cors, cors, *same-origin
                cache: "no-cache", // *default, no-cache, reload, force-cache, only-if-cached
                headers: {
                    "Content-Type": "application/json",
                    "Authorization": "Basic " + getLoginToken(),
                },
                redirect: "follow", // manual, *follow, error
                referrer: "no-referrer", // no-referrer, *client
                // body: JSON.stringify({
                //     content: writingSpeechContent,
                // }),// body data type must match "Content-Type" header
            })
                .then(res => res.json())
                .then(res => {
                    if (res.data === null) {
                        setEmptyBazaarItems(true)
                    } else {
                        setBazaarItems(res)
                    }
                })
        }
        , [])

    //生成
    const bazaarItemsRender = bazaarItems.data.map((sell: any, index: any) =>
        <ListItemButton key={"bazaarItem_" + sell.id} disableRipple alignItems="flex-start">
            <ListItemAvatar sx={{minWidth: 0, minHeight: 0, mt: "0.8vw"}}>
                <Avatar alt="Remy Sharp" src="/static/images/avatar/1.jpg"
                        sx={{width: "2.5vw", height: "2.5vw", marginRight: "1vw"}}/>
            </ListItemAvatar>

            <ListItemText
                sx={{mt: "0.4vw", mb: "0.4vw"}}
                primary={sell.building_name}
                primaryTypographyProps={{
                    fontSize: "1.25vw",
                    fontWeight: '500',
                    lineHeight: '1.2vw',
                    minWidth: "12vw",
                    mb: '0.2vw',
                    mt: "0.4vw",
                    color: "#596a76",
                }}
                secondary="种类api暂缺 - 直城门"
                secondaryTypographyProps={{
                    fontSize: "0.7vw",
                    color: "#596a76",
                }}
            />
            <ListItemText
                sx={{mt: "0.4vw", mb: "0.4vw"}}
                primary={
                    <React.Fragment>
                        <Typography
                            sx={{display: 'inline'}}
                            component="span"
                            fontSize={"0.7vw"}
                            // variant="body2"
                            // color="text.primary"
                        >
                            供应
                        </Typography>
                        {" " + itemInfo(sell.sale_type)?.Chs}
                    </React.Fragment>
                }
                primaryTypographyProps={{
                    fontSize: "1.25vw",
                    fontWeight: '500',
                    lineHeight: '1.2vw',
                    mb: '0.2vw',
                    mt: "0.4vw",
                    color: "black",
                }}
                secondary={" " + TierToStars[sell.sale_tire]? TierToStars[sell.sale_tire]:"" }
                secondaryTypographyProps={{
                    fontSize: "0.7vw",
                    color: "#596a76",
                }}
            />
            <ListItemText
                sx={{mt: "0.4vw", mb: "0.4vw"}}
                primary={sell.sale_amount.toFixed(2)}
                primaryTypographyProps={{
                    fontSize: "1.25vw",
                    fontWeight: '300',
                    lineHeight: '1.2vw',
                    mb: '0.2vw',
                    mt: "0.4vw",
                    color: "black",
                }}
                secondary="供应数量"
                secondaryTypographyProps={{
                    fontSize: "0.7vw",
                    color: "#596a76",
                }}
            />
            <ListItemText
                sx={{mt: "0.4vw", mb: "0.4vw"}}
                primary={
                    <React.Fragment>
                        <Typography
                            sx={{display: 'inline'}}
                            component="span"
                            fontSize={"0.7vw"}
                            // variant="body2"
                            // color="text.primary"
                        >
                            交换
                        </Typography>
                        {" " + itemInfo(sell.price_type)?.Chs}
                    </React.Fragment>
                }
                primaryTypographyProps={{
                    fontSize: "1.25vw",
                    fontWeight: '500',
                    lineHeight: '1.2vw',
                    mb: '0.2vw',
                    mt: "0.4vw",
                    color: "black",
                }}
                secondary={" " + TierToStars[sell.price_tire] ? TierToStars[sell.price_tire] : ""}
            secondaryTypographyProps={{
                    fontSize: "0.7vw",
                    color: "#596a76",
                }}
            />
            <ListItemText
                sx={{mt: "0.4vw", mb: "0.4vw"}}
                primary={sell.price.toFixed(2)}
                primaryTypographyProps={{
                    fontSize: "1.25vw",
                    fontWeight: '300',
                    lineHeight: '1.2vw',
                    mb: '0.2vw',
                    mt: "0.4vw",
                    color: "#ed6c02",
                }}
                secondary="单位价格"
                secondaryTypographyProps={{
                    fontSize: "0.7vw",
                    color: "#596a76",
                }}
            />
            <TextField sx={{
                "& > :not(style)": {
                    m: "0.8vw 1vw",
                    height: "2vw",
                    width: "5vw",
                    fontSize: '1.2vw',
                    backgroundColor: "white",
                    // lineHeight: "1.8em"
                }
            }}
                       id="outlined-basic"
                // label="数量"
                       variant="outlined"
                       margin="none"
            />
            <Button variant="text" className={"modify-order"}
                    style={{
                        margin: "0.8vw auto",
                        maxHeight: '1.8vw',
                        minHeight: '2vw',
                        maxWidth: "4vw",
                        minWidth: "4vw",
                        fontSize: '0.8vw',
                        color: "#ed6c02",
                        borderColor: "#ed6c02",
                        backgroundColor: "white",
                        padding: 0,
                    }}>
                交易
            </Button>
        </ListItemButton>
    )

    return (

        <div className="bazaarRoot">
            <div className={"left-container"}>
                <div className={"left-menu-container"}>
                    <div className={"left-menu-goods"}>
                        <img src={require('./assets/goods.webp').default} alt={""}/>
                    </div>
                    <div className={"left-menu-buildings"}>
                        <img src={require('./assets/buildings.webp').default} alt={""}/>
                    </div>
                </div>
            </div>
            <Divider orientation="vertical"
                     variant="middle"
                     className="middle-divider"
            />
            <div className={"right-container"}>

                {/*TODO:以下商品过滤器*/}

                <div className={"selectors-container"}>
                    <div className={"selectors-container-container"}>
                        <FormControl sx={{m: "0.3vw",width:"10vw", maxWidth: "10vw"}}>
                            <TextField select label="收货库房123123"   size="small"
                                       value={3}
                                       // helperText="Please select your currency"
                            >
                                <MenuItem value={1}>我的私人库房</MenuItem>
                                <MenuItem value={2}>我的私人12222222222222222</MenuItem>
                                <MenuItem value={3}>我</MenuItem>
                            </TextField>

                        </FormControl>
                        <FormControl sx={{m: "0.3vw", width: "10vw"}}>
                            <TextField  label="14fada"   size="small"/>

                        </FormControl>
                        <FormControl sx={{m: "0.3vw", minWidth: "6vw"}}>
                            <InputLabel htmlFor="grouped-native-select"
                                        sx={{ mt: "-5px"}}>所需货物</InputLabel>
                            <Select id="grouped-native-select" label="选择库房" >
                            </Select>
                        </FormControl>
                        <FormControl sx={{m: "0.3vw", minWidth: "6vw"}}>
                            <InputLabel htmlFor="grouped-native-select"
                                        sx={{fontSize: "0.8vw", mt: "-5px"}}>所需等级</InputLabel>
                            <Select id="grouped-native-select" label="选择库房" sx={{fontSize: "0.8vw"}}>
                            </Select>
                        </FormControl>
                        <FormControl sx={{m: "0.3vw", minWidth: "6vw"}}>
                            <InputLabel htmlFor="grouped-native-select"
                                        sx={{fontSize: "0.8vw", mt: "-5px"}}>出售货物</InputLabel>
                            <Select id="grouped-native-select" label="选择库房" sx={{fontSize: "0.8vw"}}>
                            </Select>
                        </FormControl>
                        <FormControl sx={{m: "0.3vw", minWidth: "6vw"}}>
                            <InputLabel htmlFor="grouped-native-select"
                                        sx={{fontSize: "0.8vw", mt: "-5px"}}>出售等级</InputLabel>
                            <Select id="grouped-native-select" label="选择库房" sx={{fontSize: "0.8vw"}}>
                            </Select>
                        </FormControl>
                    </div>
                    <div className={"modify-order-container"}>
                        <Button variant="outlined" className={"modify-order"}
                                style={{
                                    marginTop: "0.25vw",
                                    padding: 0,
                                    maxWidth: "7vw",
                                    minWidth: "6vw",
                                    maxHeight: '1.8vw',
                                    minHeight: '2vw',
                                    fontSize: '0.8vw',
                                    color: "#ed6c02",
                                    borderColor: "#ed6c02"
                                }}>
                            调整订单(4)
                        </Button>
                    </div>
                </div>
                <Divider variant="middle"
                         className="middle-divider"
                />

                {/*TODO:以下商品列表*/}

                <div className={"goods-list-container"}>
                    <List sx={{
                        width: '100%',
                        maxWidth: "100%",
                        padding: "0",
                        // backgroundColor: 'gray'
                    }}>
                        {emptyBazaarItems ? <div/> : bazaarItemsRender}

                    </List>
                </div>
            </div>

        </div>
    )
}

