function Index(props: {
    id: number,
    buildingType: number,
    worker_count: number,
    today_worked_count: number,
    max_storage_capacity: number,
    storage_capacity: number
    stage: number,
}) {
    // const chartType = buildingTypeToFlowChartType[props.buildingType];
    if (props.stage === 0 || props.stage === 1) {
        //没有建完的建筑
        return <div className={"building-flow-chart"}>
            <NavButtonFacilitiesWithRouter to={`/game/building/${props.id}/facilities`}
                                           id={props.id} type={props.buildingType}/>
            <NavButtonWorksSmallInOut1WithRouter to={`/game/building/${props.id}/works`}
                                                 id={props.id}
                                                 label={'开垦'}
                                                 worker_count={props.worker_count}
                                                 today_worked_count={props.today_worked_count}
            />
            <NavButtonWorksSmallInOut2WithRouter to={`/game/building/${props.id}/works`}
                                                 id={props.id}
                                                 label={'建造'}
                                                 worker_count={props.worker_count}
                                                 today_worked_count={props.today_worked_count}
            />
            <NavButtonSupervisorWithRouter to={`/game/building/${props.id}/supervisor`} id={props.id}/>
            <NavButtonOutputWithRouter to={`/game/building/${props.id}/storage`}
                                       id={props.id}
                                       label={'产出'}
                                       max_storage_capacity={props.max_storage_capacity}
                                       storage_capacity={props.storage_capacity}
            />
        </div>;
    } else {
        switch (props.buildingType) {
            case 4:
                //餐馆，普通加点餐卡。设施 工具 工作（写作烹饪实际上就是工作面板） 点餐 监工 库存
                return <div className={"building-flow-chart"}>
                    <NavButtonFacilitiesWithRouter to={`/game/building/${props.id}/facilities`}
                                                   id={props.id} type={props.buildingType}/>
                    <NavButtonToolsWithRouter to={`/game/building/${props.id}/tools`}
                                              id={props.id}
                    />
                    <NavButtonWorksSmallOutWithRouter to={`/game/building/${props.id}/works`}
                                                      id={props.id}
                                                      label={'烹饪'}
                                                      worker_count={props.worker_count}
                                                      today_worked_count={props.today_worked_count}
                    />
                    <NavButtonOrderFoodWithRouter to={`/game/building/${props.id}/OrderFood`}
                                                  id={props.id}
                    />
                    <NavButtonSupervisorWithRouter to={`/game/building/${props.id}/supervisor`} id={props.id}/>

                    <NavButtonOutputWithRouter to={`/game/building/${props.id}/storage`}
                                               id={props.id}
                                               label={'库存'}
                                               max_storage_capacity={props.max_storage_capacity}
                                               storage_capacity={props.storage_capacity}
                    />
                </div>;
                break;
            case 5:
                //藏身处
                return <div className={"building-flow-chart"}>
                    <NavButtonFacilitiesWithRouter to={`/game/building/${props.id}/facilities`}
                                                   id={props.id} type={props.buildingType}/>
                    <ShortDoubleArrow2 to={`/game/building/${props.id}/library`} LUText={"0"} LDText={"藏书数目"}
                                       label={"藏书"}/>
                    <ShortDoubleArrow1 to={`/game/building/${props.id}/recipe`} LUText={"0"} LDText={"食谱数目"}
                                       label={"食谱"}/>
                    <HighDoubleArrow1 to={`/game/building/${props.id}/residence`} LUText={"风餐露宿"} LDText={"住宿水平"}
                                      label={"住宿"}/>

                    <NavButtonOutputWithRouter to={`/game/building/${props.id}/storage`}
                                               id={props.id}
                                               label={'库存'}
                                               max_storage_capacity={props.max_storage_capacity}
                                               storage_capacity={props.storage_capacity}
                    />
                </div>;
                break;
            case 37:
            case 38:
            case 39:
                //宅院/楼房/棚屋？我别墅呢。藏身处不算
                return <div className={"building-flow-chart"}>
                    <NavButtonFacilitiesWithRouter to={`/game/building/${props.id}/facilities`}
                                                   id={props.id} type={props.buildingType}/>
                    <HighDoubleArrow1 to={`/game/building/${props.id}/guestRooms`} LUText={"0/2"} LDText={"已入住"}
                                      label={"客房"}/>
                    <NavButtonSupervisorWithRouter to={`/game/building/${props.id}/supervisor`} id={props.id}/>

                    <NavButtonOutputWithRouter to={`/game/building/${props.id}/storage`}
                                               id={props.id}
                                               label={'库存'}
                                               max_storage_capacity={props.max_storage_capacity}
                                               storage_capacity={props.storage_capacity}
                    />
                </div>;
                break;
            //所有普通生产建筑
            default:
                return <div className={"building-flow-chart"}>
                    <NavButtonFacilitiesWithRouter to={`/game/building/${props.id}/facilities`}
                                                   id={props.id} type={props.buildingType}/>
                    <NavButtonToolsWithRouter to={`/game/building/${props.id}/tools`}
                                              id={props.id}
                    />
                    <NavButtonWorksWithRouter to={`/game/building/${props.id}/works`}
                                              id={props.id}
                                              worker_count={props.worker_count}
                                              today_worked_count={props.today_worked_count}
                    />
                    <NavButtonSupervisorWithRouter to={`/game/building/${props.id}/supervisor`} id={props.id}/>
                    {/*<NavButtonSupervisorWithRouter to={`/game/building/${props.id}/OrderFood`}*/}
                    {/*                               id={props.id}*/}
                    {/*/>*/}
                    <NavButtonOutputWithRouter to={`/game/building/${props.id}/storage`}
                                               id={props.id}
                                               label={'产出'}
                                               max_storage_capacity={props.max_storage_capacity}
                                               storage_capacity={props.storage_capacity}
                    />
                </div>;
        }
    }
}

