import {createSlice} from '@reduxjs/toolkit';
import {getLoginToken} from "./utils/storage";
import {api_host} from "./utils/api";

const slice = createSlice({
    name: 'myBuildings',
    initialState: {
        "data": {
            "count": 1,
            "buildings":
                [
                    {
                        "id": 6,
                        "owner": {
                            "uid": 4,
                            "nick_name": "fetching",
                            "avatar": "",
                            "born_city": 0
                        },
                        "owner_id": 4,
                        "manager": {
                            "uid": 4,
                            "nick_name": "player",
                            "avatar": "",
                            "born_city": 0
                        },
                        "manager_id": 4,
                        "name": "fetching building",
                        "avatar": "",
                        "type": 5,
                        "tier": 1,
                        "storage_capacity": 42419.67081173745,
                        "max_storage_capacity": 100000,
                        "belong_city": 0,
                        "belong_districts": 0,
                        "belong_terrain": 0,
                        "culture": 0,
                        "stage": 2,
                        "percent": 100,
                        "product_type": 0,
                        "architect": 4
                    }
                ]
        },
        "status": "success",
        "fetchNow": 0,
    },
    reducers: {
        updateMyBuildingsWPayload: (state, action) => {
            state.data = action.payload;
        },
        fetchMyBuildingsNow: (state) => {
            state.fetchNow += 1;
        },
        fetchMyBuildings: (state) => {

            fetch(api_host() + "/api/user", {
                method: "GET", // *GET, POST, PUT, DELETE, etc.
                mode: "cors", // no-cors, cors, *same-origin
                cache: "no-cache", // *default, no-cache, reload, force-cache, only-if-cached
                headers: {
                    "Content-Type": "application/json",
                    "Authorization": "Basic " + getLoginToken(),
                },
                redirect: "follow", // manual, *follow, error
                referrer: "no-referrer", // no-referrer, *client
                // body: JSON.stringify({
                //     content: writingSpeechContent,
                // }),// body data type must match "Content-Type" header
            })
                .then(res => {
                    if (res.status === 401)
                        // navigate("/login")
                        return res.json()
                })
                .then(res => {
                        state.data = res.data;
                        state.status = res.status
                    },
                );

            // fetch(api_host() + "/api/status", {
            //     method: "GET", // *GET, POST, PUT, DELETE, etc.
            //     mode: "cors", // no-cors, cors, *same-origin
            //     cache: "no-cache", // *default, no-cache, reload, force-cache, only-if-cached
            //     headers: {
            //         "Content-Type": "application/json",
            //         "Authorization": "Basic " + getLoginToken(),
            //     },
            //     redirect: "follow", // manual, *follow, error
            //     referrer: "no-referrer", // no-referrer, *client
            //     // body: JSON.stringify({
            //     //     content: writingSpeechContent,
            //     // }),// body data type must match "Content-Type" header
            // })
            //     .then(res => res.json())
            //     .then(res => {
            //         state.data = res.data;
            //         state.status=res.status;
            //     })
        },

    },
});
export const {updateMyBuildingsWPayload, fetchMyBuildings, fetchMyBuildingsNow} = slice.actions;


