import {useDispatch, useSelector} from "react-redux";
import {useEffect, useRef} from "react";
import {api_host} from "../../utils/api";
import {getLoginToken, setBPBuildings,setBPItems,setBPSkills} from "../../utils/storage";
import {updateStateWPayload} from "../../appStateSlice";
import {updateMyHideOutStorageWPayload} from "../../myHideOutStorageSlice";
import {useNavigate} from "react-router-dom";
import {updateStatusWPayload} from "../../appSlice";
import {updateCityStructureWPayload} from "../../appCitytStructureSlice";
import {updateMyBuildingsWPayload} from "../../myBuildingsSlice";


export default function FirstFetch(){

    const dispatch = useDispatch();
    const fetchStateNow = useSelector((state: any) => state.state.fetchNow)
    const navigate = useNavigate()


    useEffect(() => {
        //自己
        fetch(api_host() + "/api/user", {
            method: "GET", // *GET, POST, PUT, DELETE, etc.
            mode: "cors", // no-cors, cors, *same-origin
            cache: "no-cache", // *default, no-cache, reload, force-cache, only-if-cached
            headers: {
                "Content-Type": "application/json",
                "Authorization": "Basic " + getLoginToken(),
            },
            redirect: "follow", // manual, *follow, error
            referrer: "no-referrer", // no-referrer, *client
            // body: JSON.stringify({
            //     content: writingSpeechContent,
            // }),// body data type must match "Content-Type" header
        })
            .then(res => {
                if (res.status === 401) navigate("/login")
                return res.json()
            })
            .then(res => {
                    if (res.status === "success") {
                        dispatch(updateStateWPayload(res.data))
                    }
                },
            );

        //自己本城市的藏身处
        fetch(api_host() + "/api/hideout", {
            method: "GET", // *GET, POST, PUT, DELETE, etc.
            mode: "cors", // no-cors, cors, *same-origin
            cache: "no-cache", // *default, no-cache, reload, force-cache, only-if-cached
            headers: {
                "Content-Type": "application/json",
                "Authorization": "Basic " + getLoginToken(),
            },
            redirect: "follow", // manual, *follow, error
            referrer: "no-referrer", // no-referrer, *client
            // body: JSON.stringify({
            //     content: writingSpeechContent,
            // }),// body data type must match "Content-Type" header
        })
            .then(res => res.json())
            .then(res => {
                if (res.isSuccess === true) {
                    dispatch(updateMyHideOutStorageWPayload(res.data))
                }
                },
            );


    }, [fetchStateNow])
    const fetchStatusNow = useSelector((state: any) => state.status.fetchNow)
    const fetchCityStructureNow = useSelector((state: any) => state.cityStructure.fetchNow)

    useEffect(() => {
        //自己的相关status
        fetch(api_host() + "/api/status", {
            method: "GET", // *GET, POST, PUT, DELETE, etc.
            mode: "cors", // no-cors, cors, *same-origin
            cache: "no-cache", // *default, no-cache, reload, force-cache, only-if-cached
            headers: {
                "Content-Type": "application/json",
                "Authorization": "Basic " + getLoginToken(),
            },
            redirect: "follow", // manual, *follow, error
            referrer: "no-referrer", // no-referrer, *client
            // body: JSON.stringify({
            //     content: writingSpeechContent,
            // }),// body data type must match "Content-Type" header
        })
            .then(res => res.json())
            .then(res => {
                if (res.status === "success") {
                    dispatch(updateStatusWPayload(res.data))
                }


                //本地城市
                // fetch(api_host() + `/api/city/3`, {
                fetch(api_host() + `/api/city/${res.data.now_city}`, {
                    method: "GET", // *GET, POST, PUT, DELETE, etc.
                    mode: "cors", // no-cors, cors, *same-origin
                    cache: "no-cache", // *default, no-cache, reload, force-cache, only-if-cached
                    headers: {
                        "Content-Type": "application/json",
                        "Authorization": "Basic " + getLoginToken(),
                    },
                    redirect: "follow", // manual, *follow, error
                    referrer: "no-referrer", // no-referrer, *client
                    // body: JSON.stringify({
                    //     content: writingSpeechContent,
                    // }),// body data type must match "Content-Type" header
                })
                    .then(res => {
                        if (res.status === 401) navigate("/login")
                        return res.json()
                    })
                    .then(res => {
                            if (res.status !== undefined) {
                                dispatch(updateCityStructureWPayload(res.data))
                            }
                        },
                    );


            })

    }, [fetchStatusNow, fetchCityStructureNow])


    //所有数值设计。街区，总览，蓝图模式可选建筑列表。
    //建筑
    useEffect(() => {
        fetch(api_host() + "/api/BPModeBuildingsList", {
            method: "GET", // *GET, POST, PUT, DELETE, etc.
            mode: "cors", // no-cors, cors, *same-origin
            cache: "no-cache", // *default, no-cache, reload, force-cache, only-if-cached
            headers: {
                "Content-Type": "application/json",
                "Authorization": "Basic " + getLoginToken(),
            },
            redirect: "follow", // manual, *follow, error
            referrer: "no-referrer", // no-referrer, *client
            // body: JSON.stringify({
            //     content: writingSpeechContent,
            // }),// body data type must match "Content-Type" header
        })
            .then(res => {
                if (res.status === 401) navigate("/login")
                return res.json()
            })
            .then(res => {
                    if (res.status === "success") {
                        setBPBuildings(res.data)
                    }
                },
            );
        //技能
        fetch(api_host() + "/api/BPModeSkillsList", {
            method: "GET", // *GET, POST, PUT, DELETE, etc.
            mode: "cors", // no-cors, cors, *same-origin
            cache: "no-cache", // *default, no-cache, reload, force-cache, only-if-cached
            headers: {
                "Content-Type": "application/json",
                "Authorization": "Basic " + getLoginToken(),
            },
            redirect: "follow", // manual, *follow, error
            referrer: "no-referrer", // no-referrer, *client
            // body: JSON.stringify({
            //     content: writingSpeechContent,
            // }),// body data type must match "Content-Type" header
        })
            .then(res => {
                if (res.status === 401) navigate("/login")
                return res.json()
            })
            .then(res => {
                    if (res.status === "success") {
                        setBPSkills(res.data)
                    }
                },
            );
        //物品
        fetch(api_host() + "/api/BPModeItemsList", {
            method: "GET", // *GET, POST, PUT, DELETE, etc.
            mode: "cors", // no-cors, cors, *same-origin
            cache: "no-cache", // *default, no-cache, reload, force-cache, only-if-cached
            headers: {
                "Content-Type": "application/json",
                "Authorization": "Basic " + getLoginToken(),
            },
            redirect: "follow", // manual, *follow, error
            referrer: "no-referrer", // no-referrer, *client
            // body: JSON.stringify({
            //     content: writingSpeechContent,
            // }),// body data type must match "Content-Type" header
        })
            .then(res => {
                if (res.status === 401) navigate("/login")
                return res.json()
            })
            .then(res => {
                    if (res.status === "success") {
                        setBPItems(res.data)
                    }
                },
            );

    }, [])


    //我拥有的建筑列表，我的建筑
    const fetchMyBuildingsNow = useSelector((state: any) => state.myBuildings.fetchNow)
    useEffect(() => {
        fetch(api_host() + "/api/buildings/my", {
            method: "GET", // *GET, POST, PUT, DELETE, etc.
            mode: "cors", // no-cors, cors, *same-origin
            cache: "no-cache", // *default, no-cache, reload, force-cache, only-if-cached
            headers: {
                "Content-Type": "application/json",
                "Authorization": "Basic " + getLoginToken(),
            },
            redirect: "follow", // manual, *follow, error
            referrer: "no-referrer", // no-referrer, *client
            // body: JSON.stringify({
            //     content: writingSpeechContent,
            // }),// body data type must match "Content-Type" header
        })
            .then(res => res.json())
            .then(res => {
                    if (res.status === "success") {
                        dispatch(updateMyBuildingsWPayload(res.data))
                    }
                },
            );
    }, [fetchMyBuildingsNow ])










}