import {createSlice} from '@reduxjs/toolkit';
import {getLoginToken} from "../utils/storage";
import {api_host} from "../utils/api";

const slice = createSlice({
    name: 'myTransactions',
    initialState: {
        "data": {
            "count": 1,
            "transactions":
                [{
                    "id": 1,
                    //交易状态：0未决1已完成2已取消3被拒4已超时
                    "status": 1,
                    "city": 0,
                    "initiate_time": 1652515476872692000,
                    "expire_time": 1652601876872692000,
                    "text_message": "",
                    "initiator": {
                        "id": 4,
                        "name": "加载中",
                        "export_building": 6,
                        "import_building": 6,
                        "fresh_only": false,
                        "pay": {
                            "items": [
                                {
                                    "type": 5,
                                    "tier": 1,
                                    "quantity": 0
                                }
                            ],
                            "buildings": []
                        }
                    },
                    "recipient": {
                        "id": 4,
                        "name": "加载中",
                        "recommended_export_building": 6,
                        "fresh_only": false,
                        "pay": {
                            "items": [
                                {
                                    "type": 5,
                                    "tier": 1,
                                    "quantity": 0
                                }
                            ],
                            "buildings": []
                        }
                    }
                },

                ]
        },
        "status": "success",
        "fetchNow": 0,
    },
    reducers: {
        updateMyTransactionsWPayload: (state, action) => {
            state.data = action.payload;
        },
        fetchMyTransactionsNow: (state) => {
            state.fetchNow += 1;
        },
        fetchMyTransactions: (state) => {

            fetch(api_host() + "/api/user", {
                method: "GET", // *GET, POST, PUT, DELETE, etc.
                mode: "cors", // no-cors, cors, *same-origin
                cache: "no-cache", // *default, no-cache, reload, force-cache, only-if-cached
                headers: {
                    "Content-Type": "application/json",
                    "Authorization": "Basic " + getLoginToken(),
                },
                redirect: "follow", // manual, *follow, error
                referrer: "no-referrer", // no-referrer, *client
                // body: JSON.stringify({
                //     content: writingSpeechContent,
                // }),// body data type must match "Content-Type" header
            })
                .then(res => {
                    if (res.status === 401)
                        // navigate("/login")
                        return res.json()
                })
                .then(res => {
                        state.data = res.data;
                        state.status = res.status
                    },
                );

            // fetch(api_host() + "/api/status", {
            //     method: "GET", // *GET, POST, PUT, DELETE, etc.
            //     mode: "cors", // no-cors, cors, *same-origin
            //     cache: "no-cache", // *default, no-cache, reload, force-cache, only-if-cached
            //     headers: {
            //         "Content-Type": "application/json",
            //         "Authorization": "Basic " + getLoginToken(),
            //     },
            //     redirect: "follow", // manual, *follow, error
            //     referrer: "no-referrer", // no-referrer, *client
            //     // body: JSON.stringify({
            //     //     content: writingSpeechContent,
            //     // }),// body data type must match "Content-Type" header
            // })
            //     .then(res => res.json())
            //     .then(res => {
            //         state.data = res.data;
            //         state.status=res.status;
            //     })
        },

    },
});
export const {updateMyTransactionsWPayload, fetchMyTransactions, fetchMyTransactionsNow} = slice.actions;


