import "./AddPhotoAvt.scss"
import {AddPhotoAlternate} from "@mui/icons-material";
import {Avatar} from "@mui/material";
import * as React from "react";

export default function AddPhotoAvt(props: {
    src: string,
    onClick: () => void,
    size?: number,
    letter?: string,
}) {
    const size = props.size ? props.size : 6
    const letter = props.letter? props.letter:""
    return <div className={"add-photo-avt-root"}  style={{borderRadius:`${0.07 * size}vw`}}>
        <div className={"backdrop"}  style={{borderRadius:`${0.07 * size}vw`}}>
            <AddPhotoAlternate/>
            <div className={"add-photo"}>添加照片</div>
        </div>
        <Avatar className={"pfp-avt"} alt={props.src}
                variant="rounded"
                src={props.src}
                style={{ width: `${size}vw`, height: `${size}vw` }}
        >{letter}
        </Avatar>
    </div>
}