import {createSlice} from '@reduxjs/toolkit';
import {getLoginToken} from "../../../utils/storage";
import {api_host} from "../../../utils/api";

const slice = createSlice({
    name: 'storage',
    initialState: {
        "data": [
            {
                "id": 1,
                "item_type": 1,
                "item_tire": 1,
                // "item_in_storage": "大量",
                // "fresh_item_in_storage": "少量",
                // "item_soling": "少量",
                // "fresh_item_soling": "微量",
                // "total_weight": "大量"
            },
        ],
        "status": "success",
        "fetchNow": 0,
    },
    reducers: {
        updateStorageWPayload: (state, action) => {
            state.data = action.payload;
        },
        fetchStorageNow: (state) => {
            state.fetchNow += 1;
        },
        fetchStorage: (state) => {

            fetch(api_host() + "/api/user", {
                method: "GET", // *GET, POST, PUT, DELETE, etc.
                mode: "cors", // no-cors, cors, *same-origin
                cache: "no-cache", // *default, no-cache, reload, force-cache, only-if-cached
                headers: {
                    "Content-Type": "application/json",
                    "Authorization": "Basic " + getLoginToken(),
                },
                redirect: "follow", // manual, *follow, error
                referrer: "no-referrer", // no-referrer, *client
                // body: JSON.stringify({
                //     content: writingSpeechContent,
                // }),// body data type must match "Content-Type" header
            })
                .then(res => {
                    if (res.status === 401)
                        // navigate("/login")
                        return res.json()
                })
                .then(res => {
                        state.data = res.data;
                        state.status = res.status
                    },
                );

            // fetch(api_host() + "/api/status", {
            //     method: "GET", // *GET, POST, PUT, DELETE, etc.
            //     mode: "cors", // no-cors, cors, *same-origin
            //     cache: "no-cache", // *default, no-cache, reload, force-cache, only-if-cached
            //     headers: {
            //         "Content-Type": "application/json",
            //         "Authorization": "Basic " + getLoginToken(),
            //     },
            //     redirect: "follow", // manual, *follow, error
            //     referrer: "no-referrer", // no-referrer, *client
            //     // body: JSON.stringify({
            //     //     content: writingSpeechContent,
            //     // }),// body data type must match "Content-Type" header
            // })
            //     .then(res => res.json())
            //     .then(res => {
            //         state.data = res.data;
            //         state.status=res.status;
            //     })
        },

    },
});
export const {updateStorageWPayload, fetchStorageNow, fetchStorage} = slice.actions;


// The function below is called a selector and allows us to select a value from
// the state. Selectors can also be defined inline where they're used instead of
// in the slice file. For example: `useSelector((state) => state.counter.value)`
// export const selectStatus = (state:any) => state.status;
// export const selectStatusFetchNow = (state:any) => state.status.fetchNow;


export default slice.reducer;
