import "./Sell.scss"
import TransitModal from "../Transit";
import {useDispatch, useSelector} from "react-redux";
import {Close} from "@mui/icons-material";
import {StorageBullet} from "../../components/BuildingBulletRender";
import {Avatar, Button, Checkbox, InputAdornment, MenuItem, Select, TextField} from "@mui/material";
import {ifNumberFloor2, itemInfo} from "../../../../components/gadgets";
import {TierToStars} from "../../../../components/mappingTable";
import {LoadingButton} from "@mui/lab";
import * as React from "react";
import {Item} from "../../../../components/IconImg";
import ItemSelector from "../../../../components/ItemSelector";
import {useState} from "react";
import {current} from "@reduxjs/toolkit";

export default function SellModal(props: {
    close: () => void
    storageCheckBox: any[]
    storage: any[]
    // onWorkDone: (status: any, message: any) => void
}) {
    const dispatch = useDispatch()
    const buildingSummary = useSelector((state: any) => state.buildingSummary.data)
    const city = useSelector((state: any) => state.cityStructure.data)
    const myHideOutStorage = useSelector((state: any) => state.myHideOutStorage.data)
    const myBuildings = useSelector((state: any) => state.myBuildings.data)
    //checkbox里面true的index的array。内容是storage物品arr的部分index。
    const trueArr = props.storageCheckBox.reduce(
        (out, bool, index) => bool ? out.concat(index) : out,
        []
    )
    //storage里面选了的item的array
    let itemArr = [...trueArr]
    itemArr?.map((item: any, index: number) =>
        itemArr[index] = props.storage[item]
    )
    //设置的新物品的arr，和trueArr条目对应
    const [pickedItems, setPickedItems] = useState<any>(new Array(trueArr.length).fill({
        "id": -1,
        "tier": 1,
        "quantity": 0
    }))
    const pickItem = (id: number, tier: number, indexInReturn: number) => {
        setPickedItems((current: any) =>
            current.map((item: any, indexInTrueArr: number) => {
                    if (indexInTrueArr === indexInReturn) {
                        return {
                            "id": id,
                            "tier": tier,
                            "quantity": item.quantity
                        }
                    } else {
                        return item
                    }
                }
            )
        )
    }
    return <div className={"SellModal"}>
        <div className={"title-line"}>
            <Close className={"close"}/>
            <div className={"r"}>
                <div className={"title"}>出售</div>
                <div className={"sub-title"}>于集市以物易物，取你所需。</div>
            </div>
        </div>
        <div className={""}>出发建筑（此处）：</div>
        <StorageBullet building={buildingSummary}/>
        <div className={"building-line"}>
        </div>
        <div className={""}>交易物品：</div>
        {trueArr.map((ind: any, index: number) =>
            <div className={"list-item-building list-item-building-storage"}
                 key={props.storage[ind]?.item_type + "1" + props.storage[ind]?.item_tire}>
                <div className={"left side"}>
                    <div className={"starter-text"}>提供</div>
                    <Item id={props.storage[ind]?.item_type} t={props.storage[ind]?.item_tire} mr={0.5}/>
                    <div className={"two-story-text"}>
                        <div className={"up black provide-item"}>
                            <TextField size="small" label={"提供总量"}
                                       value={(props.storage[ind]?.item_in_storage)}
                                // value={props.storage[ind]?.item_in_storage ? (ifNumberFloor2(props.storage[ind]?.item_in_storage)) : ""}
                                       type={"number"}
                                       InputProps={{
                                           endAdornment: <InputAdornment position="end">
                                               /{props.storage[ind]?.item_in_storage ? (ifNumberFloor2(props.storage[ind]?.item_in_storage)) : ""}
                                           </InputAdornment>,
                                       }}
                            />

                        </div>
                        <div className={"down"}>
                            {itemInfo(props.storage[ind]?.item_type)?.Chs + TierToStars[props.storage[ind]?.item_tire]} -
                            运输损耗 0%
                        </div>
                    </div>

                </div>
                <div className={"right side"}>
                    <div className={"starter-text"}>需求</div>
                    <ItemSelector mr={0.5} pickItem={(id, tier) => pickItem(id, tier, index)}/>
                    <div className={"two-story-text required-item"}>
                        {(itemInfo(pickedItems[index].id)?.Chs) ?
                            <TextField size="small" className={"up price"} label={"单价"} type={"number"}
                                       value={1}
                                // value={props.storage[ind]?.item_in_storage ? (ifNumberFloor2(props.storage[ind]?.item_in_storage)) : ""}
                            />:
                            <div className={"up " + (itemInfo(pickedItems[index].id)?.Chs ? "" : "emphasis")}>
                                {(itemInfo(pickedItems[index].id)?.Chs ?? "选择物品") + TierToStars[pickedItems[index].tier]}
                            </div>
                        }
                        <div className={"down"}>
                            {itemInfo(pickedItems[index].id)?.Chs ?(itemInfo(pickedItems[index].id)?.Chs + TierToStars[pickedItems[index].tier]): ""} - 运输损耗 0%
                        </div>
                    </div>

                </div>
            </div>
        )}
        <div className={"buttons"}>
            <Button variant="text" className={"modify-order"}
                    style={{
                        marginTop: "0.25vw",
                        padding: 0,
                        maxWidth: "7vw",
                        minWidth: "6vw",
                        maxHeight: '1.8vw',
                        minHeight: '2vw',
                        fontSize: '0.8vw',
                        color: "#ed6c02",
                        borderColor: "#ed6c02"
                    }}
                    onClick={props.close}
            >
                取消
            </Button>
            <LoadingButton variant="outlined" className={"modify-order"}
                           loading={false}
                           style={{
                               marginTop: "0.25vw",
                               padding: 0,
                               maxWidth: "7vw",
                               minWidth: "6vw",
                               maxHeight: '1.8vw',
                               minHeight: '2vw',
                               fontSize: '0.8vw',
                               backgroundColor: "#ed6c02",
                               color: "#ffffff",
                               borderColor: "#ed6c02"
                           }}
                           onClick={() => {
                           }}
            >
                {"确认"}
            </LoadingButton>
        </div>
    </div>

}