// 如果是数字就fixed小数点后2位
import {getBPBuildings, getBPFoodMaterials, getBPFuels, getBPItems, getBPSkills, getLoginToken} from "../utils/storage";
import * as React from "react";
import {api_host} from "../utils/api";

export const ifNumberToFix2 = (input: any) => {
    if (typeof input === 'number') {
        return input.toFixed(2)
    } else {
        return input
    }
}
//如果是数字就floor到最多小数点2位
export const ifNumberFloor2 = (input: any) => {
    if (typeof input === 'number') {
        return Math.floor(input * 100) / 100
    } else {
        return input
    }
}
//floor最多小数点2位
export const Floor2 = (n: number) => {
    return Math.floor(n * 100) / 100
}
//floor最多小数点1位
export const Floor1 = (n: number) => {
    return Math.floor(n * 10) / 10
}
